sql:
SELECT departments.department_name, programs.program_id, programs.program_name
FROM departments
JOIN programs ON departments.department_id = programs.department_id;

external_knowledge:
Credits Completed: Sum of the total credits from courses that a student has enrolled in;
Total Credits Required: The total number of credits required to complete a student's program;
Percentage Completed: A measure of the student's progress in their program calculated as the ratio of credits completed to total credits required, multiplied by 100.

sql:
SELECT COUNT(*)
FROM courses
WHERE hours_per_week > 5;

SELECT grade
FROM enrollments
WHERE student_id = 1 AND course_id = 1 AND semester_id = 1;

