sql:
SELECT student_name, email
FROM students
WHERE student_id > 5;

SELECT COUNT(*) 
FROM internships 
WHERE company = 'DataLab';

SELECT student_id, AVG(cgpa) AS average_CGPA
FROM credits_accumulated
GROUP BY student_id;

external_knowledge:
- 'Foundational course' refers to the course with the lowest course ID, which in this context is 0;
- 'Initial program' and 'requirement' correspond to the program and requirement with the lowest IDs, which are 0 as well;
- 'Associated semester information' means the semester details linked to the requirement with ID 0.

sql:
SELECT p.program_name
FROM programs p
WHERE p.program_id NOT IN (SELECT c.program_id FROM courses c);

SELECT s.student_id, p.total_credits_required
FROM students s
JOIN programs p ON s.program_id = p.program_id;

SELECT DISTINCT cr.mandatory
FROM students s
JOIN course_requirements cr ON s.program_id = cr.program_id;

SELECT program_id, program_name, total_credits_required
FROM programs
WHERE total_credits_required = (SELECT MAX(total_credits_required) FROM programs);
